import { UmbTextStyles } from "@umbraco-cms/backoffice/style";
import {
  css,
  html,
  customElement,
  state,
  LitElement,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import type {
  FormDataSource,
  PreValueSourceTypeWithSettings,
} from "@umbraco-forms/generated";
import type {
  UmbPropertyDatasetElement,
  UmbPropertyValueData,
} from "@umbraco-cms/backoffice/property";
import type { UmbPropertyEditorConfig } from "@umbraco-cms/backoffice/property-editor";
import { FORMS_DATASOURCE_WORKSPACE_CONTEXT } from "../../datasource-workspace.context-token.js";
import { ProviderTypeSettingsHelper } from "../../../../provider-types/provider-type-settings-helper.class.js";

const elementName = "workspace-view-datasource-design";

@customElement(elementName)
export class UmbWorkspaceViewDataSourceDesignElement
  extends UmbElementMixin(LitElement)
  implements UmbWorkspaceViewElement
{
  @state()
  _dataSource?: FormDataSource;

  @state()
  _dataSourceType?: PreValueSourceTypeWithSettings;

  @state()
  _settingValues: Array<UmbPropertyValueData> = [];

  @state()
  _settingsConfig: Array<{ alias: string; value: UmbPropertyEditorConfig }> = [];

  @state()
  _settingsConfigLoaded: boolean = false;;

  #workspaceContext?: typeof FORMS_DATASOURCE_WORKSPACE_CONTEXT.TYPE;

  #providerTypeSettingsHelper?: ProviderTypeSettingsHelper;

  #init: Promise<unknown>;

  constructor() {
    super();

    this.#init = Promise.all([
      this.consumeContext(FORMS_DATASOURCE_WORKSPACE_CONTEXT, (instance) => {
        this.#workspaceContext = instance;
      }).asPromise(),
    ]);
  }

  async connectedCallback() {
    super.connectedCallback();

    await this.#init;
    if (!this.#workspaceContext) return;

    this._dataSource = this.#workspaceContext.getData();

    const dataSourceTypeId = this._dataSource?.formDataSourceTypeId;
    if (!dataSourceTypeId) return;

    this._dataSourceType = await this.#workspaceContext?.loadDataSourceType(
      dataSourceTypeId
    );
    if (!this._dataSourceType) return;

    this.#providerTypeSettingsHelper = new ProviderTypeSettingsHelper(
      this,
      this._dataSourceType,
      "formProviderDataSources"
    );

    await this.#providerTypeSettingsHelper.loadSettingValueConverterApis();
    await this.#initialize();
  }

  async #initialize() {
    if (!this.#workspaceContext || !this._dataSource) return;

    this._settingValues =
      await this.#providerTypeSettingsHelper!.getSettingValues(
        this._dataSource.settings
      );

    this._settingsConfig =
      await this.#providerTypeSettingsHelper!.getSettingsConfig(
        this._settingValues,
        this._dataSourceType!.settings
      );
    this._settingsConfigLoaded = true;

    // Initialize settings based on configured default values.
    if (this.#workspaceContext?.getIsNew() && this._dataSourceType) {
      const settings = structuredClone(this._dataSourceType.settings);
      for (let i = 0; i < this._dataSourceType!.settings.length; i++) {
        const setting = this._dataSourceType!.settings[i];
        if (setting.defaultValue) {
          settings[setting.alias] = setting.defaultValue;
        }
      }

      this._settingValues = settings;
    }
  }

  async #onSettingsChange(e: CustomEvent) {
    const value = (e.target as UmbPropertyDatasetElement).value;
    this._settingValues = value;

    const settings =
      await this.#providerTypeSettingsHelper!.getUpdatedSettingsForPersistence(
        value
      );

    this.#setPropertyValue("settings", settings);
  }

  #setPropertyValue(alias: string, value: unknown) {
    this.#workspaceContext?.setDataSourceProperty(alias, value);
    this.dispatchEvent(new CustomEvent("valueChange"));
  }

  render() {
    return html` <uui-box>
      <umb-property-layout
        alias="type"
        .label=${this.localize.term("general_type")}
      >
        <div slot="editor">${this._dataSourceType?.name}</div>
      </umb-property-layout>

      ${when(
        this.#providerTypeSettingsHelper && this._dataSourceType && this._settingsConfigLoaded,
        () => html`<umb-property-dataset
          .value=${this._settingValues}
          @change=${this.#onSettingsChange}
        >
          ${this._dataSourceType!.settings.map(
            (setting) => html`
              <umb-property
                ?inert=${setting.isReadOnly}
                .label=${this.#providerTypeSettingsHelper!.getLocalizedSettingDetail(
                  setting,
                  "Label",
                  setting.name
                )}
                .description=${this.#providerTypeSettingsHelper!.getLocalizedSettingDetail(
                  setting,
                  "Description",
                  setting.description
                )}
                alias=${setting.alias}
                .config=${this.#providerTypeSettingsHelper!.getPropertyConfigForSetting(
                  this._settingsConfig,
                  setting
                )}
                .appearance=${this.#providerTypeSettingsHelper!.getPropertyAppearanceForSetting(
                  setting.view
                )}
                property-editor-ui-alias=${setting.view}
              >
              </umb-property>
            `
          )}
        </umb-property-dataset>`
      )}
    </uui-box>`;
  }

  static styles = [
    UmbTextStyles,
    css`
      :host {
        display: flex;
        flex-direction: column;
        margin: var(--uui-size-layout-1);
      }

      [inert] {
        opacity: 0.5;
      }
    `,
  ];
}

export default UmbWorkspaceViewDataSourceDesignElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewDataSourceDesignElement;
  }
}
